class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        def backtrack(index, path):
            if index == len(num):
                if len(path) >= 3:
                    return path
                return []
            for i in range(index + 1, len(num) + 1):
                curr = num[index:i]
                if (curr[0] == '0' and len(curr) > 1) or int(curr) > 2**31 - 1:
                    continue
                if len(path) < 2:
                    res = backtrack(i, path + [int(curr)])
                    if res:
                        return res
                elif int(curr) == path[-1] + path[-2]:
                    res = backtrack(i, path + [int(curr)])
                    if res:
                        return res
            return []
        return backtrack(0, [])
